import{c as n,S as i,j as a,m as o}from"./chunks/framework.8aa1YH_s.js";const k=JSON.parse('{"title":"Khóa học (Admin)","description":"","frontmatter":{},"headers":[],"relativePath":"admin/khoa-hoc.md","filePath":"admin/khoa-hoc.md","lastUpdated":0}'),t={name:"admin/khoa-hoc.md"};function c(g,h,l,r,s,e){return i(),a("div",null,[...h[0]||(h[0]=[o('<h1 id="khoa-hoc-admin" tabindex="-1">Khóa học (Admin) <a class="header-anchor" href="#khoa-hoc-admin" aria-label="Permalink to “Khóa học (Admin)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/thematic/course</code></p><p>Khóa học là đơn vị <strong>được bán / phát hành cho học viên</strong>. Mỗi khóa thuộc một <a href="./khung-chuong-trinh">Khung chương trình</a> và có một giáo viên phụ trách.</p><h2 id="danh-sach-khoa-hoc" tabindex="-1">Danh sách khóa học <a class="header-anchor" href="#danh-sach-khoa-hoc" aria-label="Permalink to “Danh sách khóa học”">​</a></h2><p>Cột chính:</p><ul><li>Tên khóa, Ảnh bìa</li><li>Khung chương trình</li><li>Giáo viên phụ trách</li><li><strong>Loại khóa</strong> (Ôn luyện nền tảng / Ôn luyện chuyên đề / Luyện đề thi thực chiến)</li><li>Giá gốc, Giá khuyến mãi</li><li>Số chương / chuyên đề</li><li>Số học viên đã mua</li><li>Trạng thái (Công khai / Nháp / Ẩn)</li></ul><h2 id="tao-khoa-hoc" tabindex="-1">Tạo khóa học <a class="header-anchor" href="#tao-khoa-hoc" aria-label="Permalink to “Tạo khóa học”">​</a></h2><ol><li>Bấm <strong>Thêm khóa học</strong>.</li><li>Khai báo thông tin cơ bản: <ul><li><strong>Tên khóa</strong></li><li><strong>Khung chương trình</strong> (chọn từ danh sách)</li><li><strong>Giáo viên phụ trách</strong> (1 giáo viên chính)</li><li><strong>Loại khóa</strong>: <ul><li><code>1</code> - Ôn luyện nền tảng (kiến thức cơ bản)</li><li><code>2</code> - Ôn luyện chuyên đề (chia theo chủ đề)</li><li><code>3</code> - Luyện đề thi thực chiến (toàn đề full)</li></ul></li><li><strong>Ảnh bìa, Giới thiệu ngắn</strong></li></ul></li><li><strong>Thiết lập bán hàng</strong>: <ul><li><strong>Giá gốc</strong>, <strong>Giá khuyến mãi</strong></li><li><strong>Thời gian sử dụng</strong> (số ngày kể từ ngày mua)</li><li><strong>Cho phép mua thử / học thử bao nhiêu phút?</strong></li></ul></li><li><strong>Thiết lập học</strong>: <ul><li><strong>Có chuyển chương tự động hay học sinh phải hoàn thành chương trước?</strong></li><li><strong>Có giới hạn số lần làm lại bài kiểm tra?</strong></li></ul></li><li>Bấm <strong>Lưu</strong> để tạo bản nháp.</li></ol><blockquote><p>💡 Tạo bản nháp trước, <strong>thêm nội dung (chương, chuyên đề, bài giảng)</strong> rồi mới chuyển trạng thái <strong>Công khai</strong>.</p></blockquote><h2 id="cau-hinh-mo-ta-khoa-hoc-cho-trang-ban-hang" tabindex="-1">Cấu hình &quot;Mô tả khóa học&quot; cho trang bán hàng <a class="header-anchor" href="#cau-hinh-mo-ta-khoa-hoc-cho-trang-ban-hang" aria-label="Permalink to “Cấu hình &quot;Mô tả khóa học&quot; cho trang bán hàng”">​</a></h2><p>Trang <code>Đào tạo → Thông tin Khóa học</code> (<code>https://lamsonedutech.vn/admin/educate/course</code>) cho phép biên tập riêng:</p><ul><li>Mô tả dài, ảnh, video giới thiệu</li><li>Lộ trình học theo tuần</li><li>Đầu ra cam kết</li><li>Lời giới thiệu giáo viên</li></ul><p>→ Nội dung này hiển thị trên trang <strong>Giới thiệu khóa học</strong> (<code>https://lamsonedutech.vn/luyen-tap/gioi-thieu-khoa-hoc/:id</code>) của học viên.</p><h2 id="them-noi-dung-vao-khoa" tabindex="-1">Thêm nội dung vào khóa <a class="header-anchor" href="#them-noi-dung-vao-khoa" aria-label="Permalink to “Thêm nội dung vào khóa”">​</a></h2><p>Sau khi tạo khóa, vào tab <strong>Nội dung khóa</strong> (hoặc bấm <strong>Chi tiết khóa</strong>):</p><ol><li>Bấm <strong>Thêm chương</strong> → đặt tên chương (vd &quot;Chương 1: Hàm số&quot;).</li><li>Trong từng chương, bấm <strong>Thêm chuyên đề</strong>.</li><li>Trong chuyên đề, có thể thêm: <ul><li><strong>Bài giảng</strong> (video, văn bản, file)</li><li><strong>Đề kiểm tra cuối chuyên đề</strong></li></ul></li><li>Có thể kéo-thả để sắp xếp thứ tự.</li></ol><p>→ Xem chi tiết tại <a href="./chuong-chuyen-de">Chương / Chuyên đề</a> và <a href="./bai-giang">Bài giảng</a>.</p><h2 id="gan-đe-thi-cho-khoa" tabindex="-1">Gán đề thi cho khóa <a class="header-anchor" href="#gan-đe-thi-cho-khoa" aria-label="Permalink to “Gán đề thi cho khóa”">​</a></h2><ul><li><strong>Đề ôn khóa học</strong>: tạo trong <a href="./de-on-khoa-hoc">Đề ôn khóa học</a> → liên kết vào khóa.</li><li><strong>Đề kiểm tra cuối chuyên đề</strong>: tạo trong từng chuyên đề.</li><li><strong>Bài kiểm tra đầu vào</strong> của khóa: tạo từ <a href="./danh-gia-dau-vao">Đánh giá đầu vào</a> → gán vào khóa.</li></ul><h2 id="khoa-mien-phi-vs-co-phi" tabindex="-1">Khóa miễn phí vs có phí <a class="header-anchor" href="#khoa-mien-phi-vs-co-phi" aria-label="Permalink to “Khóa miễn phí vs có phí”">​</a></h2><ul><li>Đặt <strong>Giá gốc = 0</strong> ⇒ khóa miễn phí, học viên chỉ cần đăng ký để vào học.</li><li>Có phí: học viên phải mua qua <a href="/hoc-vien/gio-hang-thanh-toan">Giỏ hàng &amp; Thanh toán</a>.</li></ul><h2 id="cong-khai-an-khoa" tabindex="-1">Công khai / Ẩn khóa <a class="header-anchor" href="#cong-khai-an-khoa" aria-label="Permalink to “Công khai / Ẩn khóa”">​</a></h2><ul><li><strong>Nháp</strong> (mặc định khi mới tạo): chỉ admin và giáo viên thấy.</li><li><strong>Công khai</strong>: học viên thấy và mua được.</li><li><strong>Ẩn</strong>: học viên không tìm thấy mới; người đã mua vẫn học bình thường.</li></ul><h2 id="sao-chep-khoa-neu-he-thong-ho-tro" tabindex="-1">Sao chép khóa (nếu hệ thống hỗ trợ) <a class="header-anchor" href="#sao-chep-khoa-neu-he-thong-ho-tro" aria-label="Permalink to “Sao chép khóa (nếu hệ thống hỗ trợ)”">​</a></h2><p>Khi sang năm hoặc tạo khóa tương tự:</p><ol><li>Bấm <strong>... → Sao chép khóa</strong>.</li><li>Đặt tên mới, chọn khung mới.</li><li>Hệ thống copy toàn bộ cấu trúc + bài giảng (link video giữ nguyên).</li><li>Chỉnh sửa lại nội dung cho phù hợp.</li></ol><h2 id="xoa-khoa" tabindex="-1">Xóa khóa <a class="header-anchor" href="#xoa-khoa" aria-label="Permalink to “Xóa khóa”">​</a></h2><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Xóa khóa sẽ làm mất lịch sử học của tất cả học viên đã mua. <strong>Hãy ẩn thay vì xóa</strong> trong hầu hết trường hợp.</p></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Khóa đã có học viên mua, có sửa giá được không?</strong> → Sửa giá chỉ áp dụng cho học viên mới mua sau đó. Học viên đã mua giữ nguyên quyền học theo thời hạn.</p><p><strong>Tôi đổi giáo viên phụ trách - khóa và lớp học của giáo viên cũ sẽ ra sao?</strong> → Khóa học <strong>chuyển sang giáo viên mới</strong>. Cần thông báo cho cả 2 bên. Các lớp học cũ vẫn còn nhưng nên reassign.</p><p><strong>Học viên báo &quot;khóa đã hết hạn&quot;.</strong> → Vào chi tiết học viên → tab Khóa học → bấm <strong>Gia hạn</strong> và chọn số ngày thêm.</p>',32)])])}const d=n(t,[["render",c]]);export{k as __pageData,d as default};
